#include <bits/stdc++.h>
using namespace std;
int ans,l,r,n,m,a[1000006],sum[2003],rest;
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    int i=1,j=1;
    ans=n+1,rest=m-1,sum[a[1]]++;
    while(i<=n){
        while(rest && j<n)
            j++,rest-=(++sum[a[j]]==1);
        if(!rest)
            if(ans>j-i+1)
                ans=j-i+1,l=i,r=j;
        if(!--sum[a[i]])
            rest++;
        i++;
        j=max(j,i);
    }
    printf("%d %d",l,r);
    return 0;
}
